 * You may obtain a copy of the License at http://www.openbravo.com/legal/obcl.html 
 **********************************************************************************
 * Contributor(s):  ______________________________________.
 **********************************************************************************/
BEGIN
  IF AD_isTriggerEnabled()='N' THEN RETURN;
  END IF;
	-- Verificar registros duplciados

	-- Validación en INSERT
	IF INSERTING THEN
	  IF EXISTS (
	    SELECT 1
	    FROM scft_acct_account
	    WHERE C_Elementvalue_ID = :NEW.C_Elementvalue_ID
	           and Scft_Acctclassif_ID = :NEW.Scft_Acctclassif_ID
	      AND scft_finan_acct_ind_id = :NEW.scft_finan_acct_ind_id  -- Compara solo dentro del mismo padre
	  ) THEN
	    RAISE_APPLICATION_ERROR(-20000, '@scft_duplicatetrg@');
	  END IF;
	END IF;

-- Validación en UPDATE si cambia el Scft_Indicatoracct_ID
IF UPDATING THEN

  IF :NEW.C_Elementvalue_ID IS NOT DISTINCT FROM :OLD.C_Elementvalue_ID
     AND :NEW.Scft_Acctclassif_ID IS NOT DISTINCT FROM :OLD.Scft_Acctclassif_ID THEN
    RAISE_APPLICATION_ERROR(-20000,'@scft_duplicatetrg@');
  END IF;

  -- Validación 2: No debe existir otro registro con la misma combinación bajo el mismo padre
  SELECT COUNT(*) INTO v_exists
  FROM scft_acct_account
  WHERE scft_finan_acct_ind_id = :NEW.scft_finan_acct_ind_id
    AND C_Elementvalue_ID = :NEW.C_Elementvalue_ID
    AND Scft_Acctclassif_ID = :NEW.Scft_Acctclassif_ID
    AND scft_acct_account_id <> :NEW.scft_acct_account_id;

  IF v_exists > 0 THEN
    RAISE_APPLICATION_ERROR(-20000,'@scft_duplicatetrg@');
  END IF;
END IF;

END SCFT_ACCACT_CKNAME_TRG
